> nvim -ll is temporary

Oh. I thought `-ll` was a very useful feature, basically a drop-in replacement for `lua`

> Meanwhile, is it not possible to make the existing vim.wait available for -ll ?

It's possible. (EDIT: quite messy)

<details>
<summary>Details</summary>

```diff
diff --git a/src/nvim/lua/executor.c b/src/nvim/lua/executor.c
index 7c4e42420a..87f89f409d 100644
--- a/src/nvim/lua/executor.c
+++ b/src/nvim/lua/executor.c
@@ -31,7 +31,6 @@
 #include "nvim/event/defs.h"
 #include "nvim/event/loop.h"
 #include "nvim/event/multiqueue.h"
-#include "nvim/event/time.h"
 #include "nvim/ex_cmds.h"
 #include "nvim/ex_cmds_defs.h"
 #include "nvim/ex_getln.h"
@@ -423,21 +422,16 @@ static int nlua_schedule(lua_State *const lstate)
   return 2;
 }

-// Dummy timer callback. Used by vim.wait().
-static void dummy_timer_due_cb(TimeWatcher *tw, void *data)
+// Dummy timer callback. Used by vim.wait() outside the editor loop.
+static void dummy_uv_timer_cb(uv_timer_t *timer)
 {
-  // If the main loop is closing, the condition won't be checked again.
-  // Close the timer to avoid leaking resources.
-  if (main_loop.closing) {
-    time_watcher_stop(tw);
-    time_watcher_close(tw, dummy_timer_close_cb);
-  }
+  (void)timer;
 }

-// Dummy timer close callback. Used by vim.wait().
-static void dummy_timer_close_cb(TimeWatcher *tw, void *data)
+// Dummy timer close callback. Used by vim.wait() outside the editor loop.
+static void dummy_uv_timer_close_cb(uv_handle_t *handle)
 {
-  xfree(tw);
+  xfree(handle);
 }

 static bool nlua_wait_condition(lua_State *lstate, int *status, bool *callback_result,
@@ -512,36 +506,66 @@ static int nlua_wait(lua_State *lstate)
     fast_only = lua_toboolean(lstate, 4);
   }

-  MultiQueue *loop_events = fast_only ? main_loop.fast_events : main_loop.events;
-
-  TimeWatcher *tw = xmalloc(sizeof(TimeWatcher));
-
-  // Start dummy timer.
-  time_watcher_init(&main_loop, tw, NULL);
-  // Don't schedule the due callback, as that'll lead to two different types of events
-  // on each interval, causing the condition to be checked twice.
-  tw->events = NULL;
-  time_watcher_start(tw, dummy_timer_due_cb, (uint64_t)interval, (uint64_t)interval);
-
+  uv_loop_t *uv_loop = luv_loop(lstate);
+  bool use_main_loop = uv_loop == &main_loop.uv;
+  MultiQueue *loop_events = use_main_loop ? (fast_only ? main_loop.fast_events : main_loop.events)
+                                          : NULL;
   int pcall_status = 0;
   bool callback_result = false;
   int nresults = 0;
+  uv_timer_t *timer = NULL;
+  bool has_deadline = timeout < INT64_MAX && timeout <= (int64_t)(UINT64_MAX / 1000000);
+  uint64_t deadline = has_deadline ? os_hrtime() + (uint64_t)timeout * 1000000 : 0;

-  // Flush screen updates before blocking.
-  ui_flush();
+  if (use_main_loop) {
+    // Flush screen updates before blocking.
+    ui_flush();
+  } else {
+    // States with their own luv loop (for example -ll and Lua threads) cannot
+    // wait on main_loop, so poll that loop directly instead.
+    timer = xmalloc(sizeof(*timer));
+    int uv_status = uv_timer_init(uv_loop, timer);
+    if (uv_status != 0) {
+      xfree(timer);
+      return luaL_error(lstate, "%s", uv_strerror(uv_status));
+    }
+  }

-  LOOP_PROCESS_EVENTS_UNTIL(&main_loop,
-                            loop_events,
-                            timeout,
-                            got_int || (is_function ? nlua_wait_condition(lstate,
-                                                                          &pcall_status,
-                                                                          &callback_result,
-                                                                          &nresults)
-                                                    : false));
+  while (!(use_main_loop && got_int) && !callback_result && !pcall_status) {
+    if (is_function && nlua_wait_condition(lstate, &pcall_status, &callback_result, &nresults)) {
+      break;
+    }

-  // Stop dummy timer
-  time_watcher_stop(tw);
-  time_watcher_close(tw, dummy_timer_close_cb);
+    int64_t delay = interval;
+    if (has_deadline) {
+      uint64_t now = os_hrtime();
+      if (now >= deadline) {
+        break;
+      }
+      uint64_t remaining_ms = (deadline - now + 999999) / 1000000;
+      delay = MIN(delay, (int64_t)remaining_ms);
+    }
+
+    if (use_main_loop) {
+      LOOP_PROCESS_EVENTS(&main_loop, loop_events, delay);
+    } else {
+      int uv_status = uv_timer_start(timer, dummy_uv_timer_cb, (uint64_t)delay, 0);
+      if (uv_status != 0) {
+        uv_close((uv_handle_t *)timer, dummy_uv_timer_close_cb);
+        uv_run(uv_loop, UV_RUN_NOWAIT);
+        return luaL_error(lstate, "%s", uv_strerror(uv_status));
+      }
+
+      uv_run(uv_loop, UV_RUN_ONCE);
+      uv_timer_stop(timer);
+    }
+  }
+
+  if (timer != NULL) {
+    uv_timer_stop(timer);
+    uv_close((uv_handle_t *)timer, dummy_uv_timer_close_cb);
+    uv_run(uv_loop, UV_RUN_NOWAIT);
+  }

   if (pcall_status) {
     return lua_error(lstate);
@@ -554,7 +578,7 @@ static int nlua_wait(lua_State *lstate)
       lua_insert(lstate, -1 - nresults);
     }
     return nresults + 1;
-  } else if (got_int) {
+  } else if (use_main_loop && got_int) {
     got_int = false;
     vgetc();
     lua_pushboolean(lstate, 0);
@@ -641,6 +665,11 @@ static void nlua_common_vim_init(lua_State *lstate, bool is_thread, bool is_stan
   lua_setfield(lstate, LUA_REGISTRYINDEX, "mpack.empty_dict");
   lua_setfield(lstate, -2, "_empty_dict_mt");

+  if (!is_thread) {
+    lua_pushcfunction(lstate, &nlua_wait);
+    lua_setfield(lstate, -2, "wait");
+  }
+
   // vim.uv
   if (is_standalone) {
     // do nothing, use libluv like in a standalone interpreter
@@ -838,10 +867,6 @@ static bool nlua_state_init(lua_State *const lstate) FUNC_ATTR_NONNULL_ALL
   lua_pushcfunction(lstate, &nlua_rpcnotify);
   lua_setfield(lstate, -2, "rpcnotify");

-  // wait
-  lua_pushcfunction(lstate, &nlua_wait);
-  lua_setfield(lstate, -2, "wait");
-
   // ui_attach
   lua_pushcfunction(lstate, &nlua_ui_attach);
   lua_setfield(lstate, -2, "ui_attach");
```

</details>

> Though with https://github.com/neovim/neovim/pull/38116 if we can eliminate the C impl of vim.wait, that's another alternative

That was my thinking. Should we merge #38116 first?
